#[test]
fn clear_ignored_on_page_break_reads_as_plain_page_break() {
    let b = make_docx(
        r#"<w:p><w:r><w:t>A</w:t><w:br w:type="page" w:clear="left"/><w:t>B</w:t></w:r></w:p><w:sectPr/>"#,
        &[],
    );
    assert_opens_clean(
        &b,
        "clear on a type=page break is schema-valid (ST_BrClear + ST_BrType independent) and opens clean (ISO 29500-1 §17.18.3, §17.18.4, §17.3.3.1)",
    );
    assert_eq!(
        accept_text(&b).trim(),
        "AB",
        "A page break deletes no content (§17.18.4) and clear is ignored on a non-textWrapping break (§17.3.3.1); the break contributes no character, so accepted text is 'AB' (refs: §17.18.3, §17.3.3.1, §17.18.4)"
    );
}

#[test]
fn column_break_intra_paragraph_deletes_no_content() {
    let b = make_docx(
        r#"<w:p><w:r><w:t>A</w:t><w:br w:type="column"/><w:t>B</w:t></w:r></w:p><w:sectPr/>"#,
        &[],
    );
    assert_opens_clean(
        &b,
        "a mid-paragraph column break is conformant run content (ST_BrType includes 'column') and opens clean (ISO 29500-1 §17.3.3.1, §17.18.4)",
    );
    assert_eq!(
        accept_text(&b).trim(),
        "AB",
        "a column break relocates following text but removes no content (§17.18.4); it contributes no character, so accepted text is 'AB' (refs: §17.3.3.1, §17.18.4)"
    );
    assert_eq!(
        reject_text(&b).trim(),
        "AB",
        "no tracked changes present, so rejected text equals accepted text 'AB'; the column break is non-tracked layout markup (refs: §17.3.3.1, §17.18.4)"
    );
}

#[test]
fn ordered_breaks_in_run_all_layout_only_concatenate() {
    let b = make_docx(
        r#"<w:p><w:r><w:t>A</w:t><w:br/><w:t>B</w:t><w:cr/><w:t>C</w:t></w:r></w:p><w:sectPr/>"#,
        &[],
    );
    assert_opens_clean(
        &b,
        "a run interleaving text, br, and cr is conformant run content and opens clean (ISO 29500-1 §17.3.3.1, §17.3.3.4)",
    );
    assert_eq!(
        accept_text(&b).trim(),
        "ABC",
        "br and cr are layout-only and delete no content (§17.3.3.1/§17.3.3.4); the three text fragments concatenate in source order to 'ABC' (refs: §17.3.3.1, §17.3.3.4)"
    );
}

#[test]
fn leading_break_keeps_its_following_text_run_carrier() {
    let b = make_docx(
        r#"<w:tbl><w:tblPr/><w:tblGrid><w:gridCol w:w="4000"/></w:tblGrid><w:tr><w:tc><w:tcPr/><w:p><w:r w:rsidRPr="00112233"><w:rPr><w:b/></w:rPr><w:br/><w:t>line after break</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#,
        &[],
    );

    let xml = reserialize(&b);
    let root = xmltree::Element::parse(xml.as_bytes()).expect("parse serialized document.xml");
    fn has_joined_break_text_run(element: &xmltree::Element) -> bool {
        if element.name == "r" {
            let child_names: Vec<&str> = element
                .children
                .iter()
                .filter_map(|child| child.as_element().map(|child| child.name.as_str()))
                .collect();
            if child_names.windows(2).any(|pair| pair == ["br", "t"]) {
                return true;
            }
        }
        element
            .children
            .iter()
            .any(|child| child.as_element().is_some_and(has_joined_break_text_run))
    }

    assert!(
        has_joined_break_text_run(&root),
        "an untouched source w:r beginning with w:br and followed by w:t must rebuild as one run; a synthetic break-only run changes Word's table pagination. XML: {xml}"
    );
    assert!(
        xml.contains(r#"w:rsidRPr="00112233""#),
        "the joined carrier keeps the following text run's source attributes"
    );
}

