#[test]
fn tab_pos_at_word_max_boundary_preserved_opens_clean() {
    let b = make_docx(
        r#"<w:p><w:pPr><w:tabs><w:tab w:val="start" w:pos="31680"/></w:tabs></w:pPr><w:r><w:t>edge</w:t></w:r></w:p><w:sectPr/>"#,
        &[],
    );
    assert_opens_clean(
        &b,
        "31680 twips is exactly Word's documented maximum tab pos, in-range and valid; Word opens it without repair (ISO 29500-1 §17.3.1.37, §17.18.81, MS-OI29500 §2.1.61)",
    );
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:pos="31680""#),
        "an in-range tab pos has no clamping mandate, so it must round-trip verbatim, never clamped or dropped (§17.3.1.37, MS-OI29500 §2.1.61); reserialized document.xml was: {xml}"
    );
}

#[test]
fn nobreakhyphen_inside_hyperlink_survives_reserialize_as_u2011() {
    // Regression: a `<w:noBreakHyphen/>` leaf inside a `<w:hyperlink>` was
    // dropped on IR reserialize because the hyperlink-run text harvester only
    // collected `w:t`/`w:delText` text and recursed past non-text leaves,
    // contributing nothing. The HyperlinkRun text is a flat String, so the
    // harvester must PROJECT the leaf to its Unicode character. U+2011
    // NON-BREAKING HYPHEN is exactly the character `<w:noBreakHyphen/>` denotes
    // (ISO 29500-1 §17.3.3.18), and Word reads/renders U+2011-in-w:t
    // identically, so the projection conserves the visible content.
    //
    // The loss only manifests through `serialize_canonical_docx`, NOT through a
    // verbatim re-zip. Untouched content round-trips byte-verbatim, so we must
    // force a full body reserialization with a styles-only `SetDocDefaults`
    // edit (the prod reserialize trigger) before censusing the output.
    let b = make_docx(
        r#"<w:p><w:hyperlink w:anchor="X"><w:r><w:t>G</w:t><w:noBreakHyphen/><w:t>S.1.2.</w:t></w:r></w:hyperlink></w:p><w:sectPr/>"#,
        &[],
    );
    assert_opens_clean(
        &b,
        "a hyperlink run interleaving text and noBreakHyphen is conformant run content and opens clean (ISO 29500-1 §17.16.22 CT_Hyperlink, §17.3.3.18)",
    );

    let runtime = SimpleRuntime::new();
    let import = runtime.import_docx(&b).expect("import_docx");
    let trigger = EditTransaction {
        steps: vec![EditStep::SetDocDefaults {
            font_family: Some("Calibri".to_string()),
            font_size_half_points: None,
            rationale: Some("reserialize trigger".to_string()),
        }],
        summary: Some("reserialize trigger".to_string()),
        materialization_mode: MaterializationMode::Direct,
        revision: RevisionInfo {
            revision_id: 1,
            identity: 0,
            author: Some("spec".to_string()),
            date: Some("2026-06-29T00:00:00Z".to_string()),
            apply_op_id: None,
        },
    };
    runtime
        .apply_edit(&import.doc_handle, &trigger)
        .expect("apply_edit(SetDocDefaults) reserialize trigger");
    let out = runtime
        .export_docx(&import.doc_handle, ExportMode::Redline)
        .expect("export_docx");
    let xml = document_xml_of(&out);

    // Reserialize must not drop the hyphen: it comes back as the equivalent
    // U+2011 character carried inside the hyperlink-run text. Before the fix the
    // hyphen was erased, turning visible "G‑S.1.2." into "GS.1.2.".
    assert!(
        xml.contains('\u{2011}'),
        "the noBreakHyphen inside the hyperlink must survive IR reserialization as U+2011 (§17.3.3.18); it was dropped (flat-String hyperlink harvester ignored the non-text leaf). reserialized document.xml was: {xml}"
    );
    // The hyphen lands between the two text fragments, not appended/prepended:
    // the harvester projects the leaf in source order, yielding "G‑S.1.2." as
    // the single concatenated hyperlink-run text.
    assert!(
        xml.contains("G\u{2011}S.1.2.") || xml.contains(">G\u{2011}S.1.2.<"),
        "the projected U+2011 must sit in source order between 'G' and 'S.1.2.', preserving visible 'G‑S.1.2.' (§17.3.3.18); reserialized document.xml was: {xml}"
    );
}
